class ExamRoom {
    private int n;
    private List<Integer> seats;

    public ExamRoom(int n) {
        this.n = n;
        seats = new ArrayList<>();
    }

    public int seat() {
        if (seats.isEmpty()) {
            return 0;
        }
        int maxDist = 0;
        int seatIndex = 0;
        for (int i = 0; i < seats.size(); i++) {
            int dist = Math.min(seats.get(i), n - 1 - seats.get(i));
            if (dist > maxDist) {
                maxDist = dist;
                seatIndex = i;
            }
        }
        return seats.get(seatIndex);
    }

    public void leave(int p) {
        seats.remove((Integer) p);
    }
}
